        # Remove any non-alphanumeric characters and convert to lowercase
        cleaned = re.sub(r'[^a-zA-Z0-9\s\.\,\-\(\)]', '', input_str)
        # Normalize state abbreviations
        if re.search(r'\bnyc\b', cleaned, re.IGNORECASE):
            return 'New York City'
        # Split into parts and process each part
        parts = cleaned.split()
        normalized_parts = []
        for part in parts:
            # Check if part is a state abbreviation
            if len(part) == 2 and part.isupper():
                normalized_parts.append(normalize_state(part))
            else:
                # Normalize the part (e.g., 'n.y.c.' -> 'New York City')
                normalized_parts.append(''.join([c.upper() for c in part]))
        return ' '.join(normalized_parts)

    def format_date(date_str):
        # Parse the date string into a datetime object
        try:
            date_obj = datetime.datetime.strptime(date_str, '%Y-%m-%d')
        except ValueError:
            return date_str
        # Format the date as 'Month Day, Year'
