import re
import math
import datetime
import calendar

def transform(row):
    if re.fullmatch(r'\d{4}', row[0]):
        return row[0]
    match = re.fullmatch(r'(\d{1,2})\s?(\w+)?\s?(\d{4})', row[0])
    if match:
        return match.group(3)
    return row[0]
