import re
import math
import datetime
import calendar

def transform(row):
    def extract_year(date_str):
        match = re.match(r'\d{1,2}\s?(\d{4})', date_str)
        if match:
            return match.group(1)
        return None

    def is_number(s):
        try:
            float(s)
            return True
        except ValueError:
            return False

    def get_year_from_date(date_str):
        if is_number(date_str):
            return date_str
        year = extract_year(date_str)
        if year:
            return year
        return None

    def get_year_from_number(number_str):
        if is_number(number_str):
            return number_str
        return None

    def get_year_from_string(string):
        year = get_year_from_date(string)
        if year:
            return year
        return get_year_from_number(string)

    year = get_year_from_string(row[0])
    if year:
        return year
    return row[0]
